// src/pages/Contracts.jsx
import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/* ===================== Helpers ===================== */
const PAGE_SIZE = 10;
const VND = (v) => (Number(v || 0)).toLocaleString("vi-VN");
const parseVND = (s) => {
    if (typeof s === "number") return s;
    if (!s) return 0;
    const num = String(s).replace(/[^\d]/g, "");
    return Number(num || 0);
};
const toISO = (d) => (d ? String(d).slice(0, 10) : "");
const todayStr = () => {
    const d = new Date();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${m}-${day}`;
};
const normalizeList = (d) =>
    Array.isArray(d) ? { list: d, pages: 1 } : { list: d?.content || [], pages: d?.totalPages || 1 };

function hasAnyRole(user, allow = []) {
    if (!user) return false;
    const S = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return S.add(x.toUpperCase());
        if (typeof x === "object")
            return ["role", "name", "authority"].forEach((k) => x[k] && S.add(String(x[k]).toUpperCase()));
    };
    add(user.role); add(user.roles); add(user.authorities);
    if (S.size === 0) return true;
    return allow.some((r) => S.has(r));
}

/* ====== enums ====== */
const STATUS_OPTS = [
    { label: "Đang thực hiện", value: "ACTIVE" },
    { label: "Đã hoàn tất", value: "COMPLETED" },
    { label: "Huỷ", value: "CANCELED" },
];
const CONTRACT_TYPE_OPTS = [
    { label: "Thi công xây dựng", value: "CONSTRUCTION" },
    { label: "Bảo trì", value: "MAINTENANCE" },
    { label: "Dịch vụ", value: "SERVICE" },
];

const toLabel = (opts, v) => opts.find((o) => o.value === v || o.label === v)?.label || v || "";
const toValue = (opts, l) => opts.find((o) => o.label === l || o.value === l)?.value || l;

/* ===================== Component ===================== */
export default function Contracts() {
    const { user } = useAuth();
    const canEdit = hasAnyRole(user, ["ADMIN", "SALES"]);
    const canDelete = hasAnyRole(user, ["ADMIN"]);

    // data
    const [rows, setRows] = useState([]);
    const [customers, setCustomers] = useState([]);
    const [salesUsers, setSalesUsers] = useState([]);

    // ui state
    const [q, setQ] = useState("");
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // modal/form
    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [saving, setSaving] = useState(false);
    const [form, setForm] = useState({
        contractCode: "",
        title: "",
        contractType: "CONSTRUCTION",
        customerId: "",
        salesId: "",
        signedDate: todayStr(),
        dueDate: todayStr(),
        totalAmount: "",
        status: "ACTIVE",
    });

    /* ---------- load base data ---------- */
    useEffect(() => {
        loadContracts(0);
        loadCustomers();
        loadSales();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    useEffect(() => {
        loadContracts(page);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page]);

    async function loadContracts(p) {
        setLoading(true);
        try {
            const { data } = await api.get("/api/contracts", {
                params: { page: p, size: PAGE_SIZE, sort: "id,desc", q: q || undefined },
            });
            const { list, pages } = normalizeList(data);
            setRows(list);
            setTotalPages(pages);
            setPage(p);
        } catch (e) {
            console.error("Load contracts failed:", e);
            setRows([]); setTotalPages(1); setPage(0);
        } finally { setLoading(false); }
    }

    async function loadCustomers() {
        try {
            const { data } = await api.get("/api/customers", { params: { page: 0, size: 1000 } });
            const list = Array.isArray(data) ? data : data?.content || [];
            setCustomers(list);
        } catch (e) { console.error("Load customers failed:", e); }
    }
    async function loadSales() {
        try {
            // Ưu tiên backend hỗ trợ lọc role
            let data;
            try {
                const res = await api.get("/api/users", { params: { role: "SALES", page: 0, size: 1000 } });
                data = res.data;
            } catch {
                const res = await api.get("/api/users", { params: { page: 0, size: 1000 } });
                data = res.data;
            }
            const list = Array.isArray(data) ? data : data?.content || [];
            const filtered = list.filter((u) => {
                const r = (u.role || u.roles || "").toString().toUpperCase();
                return r.includes("SALES");
            });
            setSalesUsers(filtered.length ? filtered : list);
        } catch (e) { console.error("Load users failed:", e); }
    }

    /* ---------- derived maps ---------- */
    const customerMap = useMemo(() => {
        const m = new Map(); customers.forEach((c) => m.set(String(c.id), c)); return m;
    }, [customers]);
    const salesMap = useMemo(() => {
        const m = new Map(); salesUsers.forEach((s) => m.set(String(s.id), s)); return m;
    }, [salesUsers]);

    /* ---------- open modal ---------- */
    function openCreate() {
        setEditing(null);
        setForm({
            contractCode: "",
            title: "",
            contractType: "CONSTRUCTION",
            customerId: customers[0]?.id ? String(customers[0].id) : "",
            salesId: salesUsers[0]?.id ? String(salesUsers[0].id) : "",
            signedDate: todayStr(),
            dueDate: todayStr(),
            totalAmount: "",
            status: "ACTIVE",
        });
        setShow(true);
    }
    function openEdit(ct) {
        setEditing(ct);
        setForm({
            contractCode: ct.contractCode || "",
            title: ct.title || "",
            contractType: ct.contractType || "CONSTRUCTION",
            customerId: String(ct.customerId || ct.customer?.id || ""),
            salesId: String(ct.salesId || ct.sales?.id || ""),
            signedDate: toISO(ct.signedDate),
            dueDate: toISO(ct.dueDate),
            totalAmount: VND(ct.totalAmount || 0),
            status: ct.status || "ACTIVE",
        });
        setShow(true);
    }

    /* ---------- save/remove ---------- */
    async function save(e) {
        e.preventDefault();
        const payload = {
            contractCode: (form.contractCode || "").trim() || null, // cho phép backend tự sinh
            title: form.title?.trim(),
            contractType: toValue(CONTRACT_TYPE_OPTS, form.contractType),
            customerId: Number(form.customerId),
            salesId: Number(form.salesId) || null,
            signedDate: form.signedDate,
            dueDate: form.dueDate,
            totalAmount: parseVND(form.totalAmount),
            status: toValue(STATUS_OPTS, form.status),
        };

        // validate
        if (!payload.title) return alert("Vui lòng nhập tiêu đề hợp đồng");
        if (!payload.customerId) return alert("Vui lòng chọn khách hàng");
        if (!payload.signedDate || !payload.dueDate) return alert("Vui lòng nhập ngày ký & hạn");
        if (new Date(payload.dueDate) < new Date(payload.signedDate)) return alert("Hạn kết thúc phải sau ngày ký");
        if (!payload.totalAmount || payload.totalAmount <= 0) return alert("Tổng giá trị phải > 0");

        setSaving(true);
        try {
            if (editing) {
                await api.put(`/api/contracts/${editing.id}`, payload);
            } else {
                await api.post("/api/contracts", payload);
            }
            setShow(false);
            await loadContracts(0);
        } catch (err) {
            console.error(err);
            alert(err?.response?.data?.message || "Lưu hợp đồng thất bại");
        } finally { setSaving(false); }
    }

    async function removeRow(row) {
        if (!canDelete) return;
        if (!window.confirm("Xoá hợp đồng này?")) return;
        try {
            await api.delete(`/api/contracts/${row.id}`);
            await loadContracts(page);
        } catch (err) {
            console.error(err);
            alert(err?.response?.data?.message || "Xoá hợp đồng thất bại");
        }
    }

    /* ---------- render ---------- */
    return (
        <div className="space-y-5">
            {/* Header */}
            <div className="flex items-center justify-between gap-3">
                <div>
                    <h2 className="text-lg font-semibold">Hợp đồng</h2>
                    <p className="text-sm text-slate-500">Quản lý hợp đồng và tiến độ thanh toán</p>
                </div>
                <div className="flex items-center gap-2">
                    <input
                        value={q}
                        onChange={(e)=>setQ(e.target.value)}
                        onKeyDown={(e)=> e.key === "Enter" && loadContracts(0)}
                        placeholder="Tìm: mã/tiêu đề/khách hàng…"
                        className="px-3 py-2 rounded-xl border border-indigo-100 bg-white shadow min-w-[260px]"
                    />
                    <button
                        onClick={()=>loadContracts(0)}
                        className="px-3 py-2 rounded-xl bg-slate-100">Tìm</button>
                    {canEdit && (
                        <button
                            onClick={openCreate}
                            className="px-3 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700">
                            Thêm hợp đồng
                        </button>
                    )}
                </div>
            </div>

            {/* Table */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Mã HĐ</th>
                            <th className="px-4 py-3 text-left">Tiêu đề</th>
                            <th className="px-4 py-3 text-left">Khách hàng</th>
                            <th className="px-4 py-3 text-left">Sales</th>
                            <th className="px-4 py-3 text-left">Ngày ký</th>
                            <th className="px-4 py-3 text-left">Hạn</th>
                            <th className="px-4 py-3 text-right">Tổng</th>
                            <th className="px-4 py-3 text-right">Đã thu</th>
                            <th className="px-4 py-3 text-right">Còn lại</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr><td className="px-4 py-6" colSpan={11}>Đang tải…</td></tr>
                        ) : rows.length === 0 ? (
                            <tr><td className="px-4 py-6" colSpan={11}>Chưa có dữ liệu</td></tr>
                        ) : (
                            rows.map((c) => {
                                const code = c.contractCode || c.code || `HD-${c.id}`;
                                const cus = c.customerName || c.customer?.name || "";
                                const sales = c.salesName || c.sales?.fullName || c.sales?.username || "";
                                const total = c.totalAmount || 0;
                                const paid = c.paidAmount || 0;
                                const remain = (c.remainingAmount ?? Math.max(0, total - paid));
                                const statusLabel = toLabel(STATUS_OPTS, c.status);
                                return (
                                    <tr key={c.id} className="hover:bg-indigo-50/40">
                                        <td className="px-4 py-3 font-medium">{code}</td>
                                        <td className="px-4 py-3">{c.title}</td>
                                        <td className="px-4 py-3">{cus}</td>
                                        <td className="px-4 py-3">{sales || "-"}</td>
                                        <td className="px-4 py-3">{toISO(c.signedDate)}</td>
                                        <td className="px-4 py-3">{toISO(c.dueDate)}</td>
                                        <td className="px-4 py-3 text-right tabular-nums">{VND(total)} đ</td>
                                        <td className="px-4 py-3 text-right tabular-nums">{VND(paid)} đ</td>
                                        <td className="px-4 py-3 text-right tabular-nums">{VND(remain)} đ</td>
                                        <td className="px-4 py-3">
                        <span className={
                            "px-2 py-0.5 rounded-full text-xs " +
                            (c.status === "COMPLETED" ? "bg-emerald-100 text-emerald-700"
                                : c.status === "CANCELED" ? "bg-rose-100 text-rose-700"
                                    : "bg-amber-100 text-amber-700")
                        }>{statusLabel}</span>
                                        </td>
                                        <td className="px-4 py-3 text-right">
                                            {canEdit ? (
                                                <div className="inline-flex gap-2">
                                                    <button onClick={()=>openEdit(c)}
                                                            className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                                    {canDelete && (
                                                        <button onClick={()=>removeRow(c)}
                                                                className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xoá</button>
                                                    )}
                                                </div>
                                            ) : <span className="text-slate-400">—</span>}
                                        </td>
                                    </tr>
                                );
                            })
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2 items-center">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={()=>setPage((p)=>Math.max(0, p-1))} disabled={page<=0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page+1}/{totalPages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={()=>setPage((p)=>Math.min(totalPages-1, p+1))} disabled={page+1>=totalPages}>Sau →</button>
            </div>

            {/* Modal */}
            {show && canEdit && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa hợp đồng" : "Thêm hợp đồng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={()=>setShow(false)}>Đóng</button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            {/* Code (tuỳ backend tự sinh) */}
                            <div>
                                <label className="text-sm text-slate-600">Mã hợp đồng (tùy chọn)</label>
                                <input value={form.contractCode}
                                       onChange={(e)=>setForm(f=>({...f, contractCode:e.target.value}))}
                                       placeholder="Ví dụ: HD-20250823-17065"
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>

                            {/* Title */}
                            <div>
                                <label className="text-sm text-slate-600">Tiêu đề</label>
                                <input required value={form.title}
                                       onChange={(e)=>setForm(f=>({...f, title:e.target.value}))}
                                       placeholder="VD: Thi công nhà xưởng A"
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>

                            {/* Type */}
                            <div>
                                <label className="text-sm text-slate-600">Loại hợp đồng</label>
                                <select value={form.contractType}
                                        onChange={(e)=>setForm(f=>({...f, contractType:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {CONTRACT_TYPE_OPTS.map(o=>(
                                        <option key={o.value} value={o.value}>{o.label}</option>
                                    ))}
                                </select>
                            </div>

                            {/* Status */}
                            <div>
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select value={form.status}
                                        onChange={(e)=>setForm(f=>({...f, status:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {STATUS_OPTS.map(o=>(
                                        <option key={o.value} value={o.value}>{o.label}</option>
                                    ))}
                                </select>
                            </div>

                            {/* Customer */}
                            <div>
                                <label className="text-sm text-slate-600">Khách hàng</label>
                                <select required value={form.customerId}
                                        onChange={(e)=>setForm(f=>({...f, customerId:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {customers.map(c=>(
                                        <option key={c.id} value={c.id}>{c.name || c.customerName || `KH-${c.id}`}</option>
                                    ))}
                                </select>
                            </div>

                            {/* Sales */}
                            <div>
                                <label className="text-sm text-slate-600">Nhân viên kinh doanh</label>
                                <select value={form.salesId}
                                        onChange={(e)=>setForm(f=>({...f, salesId:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    <option value="">-- Không gán --</option>
                                    {salesUsers.map(s=>(
                                        <option key={s.id} value={s.id}>
                                            {s.fullName || s.username || `User-${s.id}`}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Dates */}
                            <div>
                                <label className="text-sm text-slate-600">Ngày ký</label>
                                <input required type="date" value={form.signedDate}
                                       onChange={(e)=>setForm(f=>({...f, signedDate:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Hạn kết thúc</label>
                                <input required type="date" value={form.dueDate}
                                       onChange={(e)=>setForm(f=>({...f, dueDate:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>

                            {/* Total */}
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Tổng giá trị (đ)</label>
                                <input required type="text" inputMode="numeric" pattern="[0-9\.]*"
                                       placeholder="VD: 1.230.000.000"
                                       value={form.totalAmount}
                                       onChange={(e)=>setForm(f=>({...f, totalAmount: VND(parseVND(e.target.value))}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow tabular-nums"/>
                            </div>

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                        onClick={()=>setShow(false)} disabled={saving}>Hủy</button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-50"
                                        disabled={saving}>{saving ? "Đang lưu..." : "Lưu"}</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
